// AUTO-GENERATED from GADM India state boundaries (geohacker/india),
// largest Karnataka ring Douglas-Peucker simplified to 713 points.
// Regenerate with the script in the repo history if the projection changes.

export const MAP_WIDTH = 425;
export const MAP_HEIGHT = 640;

const PAD = 30;
const DRAW_W = 365.140;
const DRAW_H = 580;
const LAT_MIN = 11.57448;
const LAT_MAX = 18.45512;
const LON_MIN = 74.09264;
const LON_MAX = 78.57747;

/** Projects a geographic coordinate into the map's SVG space. */
export function projectGeo(lat: number, lon: number): { x: number; y: number } {
  return {
    x: PAD + ((lon - LON_MIN) / (LON_MAX - LON_MIN)) * DRAW_W,
    y: PAD + (1 - (lat - LAT_MIN) / (LAT_MAX - LAT_MIN)) * DRAW_H,
  };
}

